const row = $input.first().json;
const analysis = typeof row.analysis === 'string' ? JSON.parse(row.analysis) : row.analysis;
const top = (analysis?.errors || [])[0] || { code: 'GENERAL', description: 'нет данных' };

function uuid() {
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, c => {
    const r = (Math.random() * 16) | 0;
    return (c === 'x' ? r : (r & 0x3) | 0x8).toString(16);
  });
}

return [{
  json: {
    session_id: uuid(),
    dialog_id: row.dialog_id,
    employee_id: row.employee_id,
    telegram_chat_id: String(row.telegram_chat_id).trim(),
    full_name: row.full_name,
    session_state: 'intro',
    user_message: '(старт сессии)',
    errors_summary: `${top.code}: ${top.description}`,
    employee_memory: 'нет',
    analysis,
    context: [],
  },
}];

const j = $input.first().json;

const phaseHint = {
  intro: 'Кратко объясни ошибку WEAK_NEEDS_DISCOVERY и предложи практику. Спроси: готов начать?',
  roleplay: 'Ты играешь КЛИЕНТА в магазине колбас. Клиент хочет нежирное, но не знает что. Ответь коротко как покупатель.',
  feedback: 'Похвали за открытые вопросы, дай 1 совет. Напиши что тренировка завершена.',
  done: 'Поблагодари и заверши тренировку одним предложением.',
}[j.session_state] || 'Продолжай тренировку.';

const system = `Ты AI-наставник по продажам в магазине колбас и мясных изделий. Только русский язык.

Фаза: ${j.session_state}
Задача: ${phaseHint}
Ошибка из диалога: ${j.errors_summary}
Сотрудник: ${j.full_name || 'продавец'}

Правила:
- 2–4 предложения, до 350 символов
- Только русский, без английских слов
- НЕ выдумывай бренды и названия магазинов
- НЕ пиши только метку состояния — сначала нормальный текст для человека
- В самом конце ответа ОТДЕЛЬНОЙ строкой: [STATE:roleplay] или [STATE:feedback] или [STATE:done]

Пример хорошего ответа:
"Мария, вы сразу предложили товар, не выяснив потребности. Давайте потренируемся: клиент хочет нежирное. Задайте 1–2 открытых вопроса."
[STATE:roleplay]`;

const history = (j.context || [])
  .map((m) => `${m.role === 'user' ? 'Сотрудник' : 'Наставник'}: ${m.text}`)
  .join('\n');

const user = `История:
${history || '(пусто)'}

Сообщение сотрудника:
${j.user_message || '(старт сессии)'}`;

return [{
  json: {
    ...j,
    ollama_body: {
      model: 'llama3.2:1b',
      stream: false,
      options: {
        temperature: 0.2,
        num_predict: 220,
      },
      messages: [
        { role: 'system', content: system },
        { role: 'user', content: user },
      ],
    },
  },
}];

const prev = $('Build Ollama Body').first().json;
const ollamaOut = $input.first().json;

const STATE_MAP = {
  intro: 'intro', roleplay: 'roleplay', feedback: 'feedback', done: 'done',
  вступление: 'intro', практика: 'roleplay', практик: 'roleplay',
  разбор: 'feedback', обратная: 'feedback', готово: 'done', завершено: 'done',
  вопрос: 'roleplay', question: 'roleplay',
};

function stripStateTags(raw) {
  let nextState = prev.session_state || 'intro';
  const tagRe = /\[(?:STATE|state)\s*:\s*([^\]\n]+)\]/gi;
  const tags = [...raw.matchAll(tagRe)];
  for (const m of tags) {
    const token = m[1].trim().toLowerCase();
    if (STATE_MAP[token]) nextState = STATE_MAP[token];
  }
  const text = raw.replace(/\[(?:STATE|state)\s*:\s*[^\]\n]+\]/gi, '').trim();
  return { text, nextState };
}

function countUserTurns(context) {
  return (context || []).filter((m) => m.role === 'user').length;
}

function scriptedReply(state, userTurns, userMessage) {
  const name = prev.full_name || 'коллега';
  const err = prev.errors_summary || 'WEAK_NEEDS_DISCOVERY';
  const msg = (userMessage || '').toLowerCase();

  if (state === 'intro' || prev.user_message === '(старт сессии)') {
    return {
      text: `Привет, ${name}! Ошибка в диалоге: ${err}. Вы сразу предложили товар, не выяснив потребности. Потренируемся: клиент хочет нежирное, но не определился. Задайте открытые вопросы — для кого покупка и что важнее?`,
      nextState: 'roleplay',
    };
  }

  if (state === 'roleplay') {
    if (userTurns >= 2 || /докторск|индейк|колбас|нежирн|нарезк/.test(msg)) {
      return {
        text: 'Отлично! Вы задали вопросы и предложили варианты — так и нужно. Совет: всегда начинайте с «Для кого выбираете?» и «Что важнее — нежирное или вкус?». Тренировка завершена!',
        nextState: 'done',
      };
    }
    if (/семь|ужин|нежир|для кого|важнее/.test(msg)) {
      return {
        text: 'Для семьи, к ужину. Хочу нежирное — докторская или индейка, не могу выбрать. Что посоветуете?',
        nextState: 'roleplay',
      };
    }
    return {
      text: 'Хочу что-то нежирное к ужину, но не знаю что выбрать. Подскажите?',
      nextState: 'roleplay',
    };
  }

  return {
    text: 'Тренировка завершена. Спасибо!',
    nextState: 'done',
  };
}

function isBadReply(text) {
  if (!text || text.length < 25) return true;
  if (/\[(?:STATE|state)\s*:/i.test(text)) return true;
  if (/берлос|домиан|продвижени|кто покупает в магазине/i.test(text)) return true;
  if (/^[\[\(]?(?:STATE|state)\s*:/i.test(text)) return true;
  return false;
}

const raw = (
  ollamaOut?.message?.content ||
  ollamaOut?.response ||
  ''
).trim();

const stripped = stripStateTags(raw);
const userTurns = countUserTurns(prev.context);
const currentState = prev.session_state || 'intro';

let text = stripped.text;
let nextState = stripped.nextState;

// llama3.2:1b ненадёжен — для пилота используем сценарные ответы
const scripted = scriptedReply(currentState, userTurns, prev.user_message);
text = scripted.text;
nextState = scripted.nextState;

if (isBadReply(text)) {
  const fb = scriptedReply(currentState, userTurns, prev.user_message);
  text = fb.text;
  nextState = fb.nextState;
}

if (text.length > 3800) text = text.slice(0, 3800) + '…';

const chatId = String(prev.telegram_chat_id || String($env.SEED_REGIONAL_TELEGRAM_CHAT_ID || '0')).trim();
const context = [...(prev.context || [])];
context.push({ role: 'assistant', text, at: new Date().toISOString() });

return [{
  json: {
    ...prev,
    coach_reply: text,
    session_state: nextState,
    context,
    context_json: JSON.stringify(context),
    telegram_body: { chat_id: chatId, text },
  },
}];

parameters.query:
UPDATE training_sessions SET
  state = '{{ $json.session_state }}',
  context = '{{ $json.context_json }}'::jsonb
WHERE session_id = '{{ $json.session_id }}'::uuid;

UPDATE dialogs SET status = 'coaching', updated_at = NOW()
WHERE dialog_id = '{{ $json.dialog_id }}'::uuid;

parameters.jsCode:
const start = $('Build Start').first().json;
const pg = $input.first().json;

return [{
  json: {
    ...start,
    session_id: pg.session_id || start.session_id,
    session_state: pg.state || start.session_state,
  },
}];

const sess = $input.first().json;
const msg = $('Parse Message').first().json;

const analysis = typeof sess.analysis === 'string'
  ? JSON.parse(sess.analysis)
  : sess.analysis;

const context = typeof sess.context === 'string'
  ? JSON.parse(sess.context)
  : (sess.context || []);

const top = (analysis?.errors || [])[0] || { code: 'GENERAL', description: '—' };

return [{
  json: {
    session_id: sess.session_id,
    dialog_id: sess.dialog_id,
    employee_id: sess.employee_id,
    telegram_chat_id: String(sess.telegram_chat_id).trim(),
    full_name: sess.full_name,
    session_state: sess.session_state || 'roleplay',
    user_message: msg.user_message,
    errors_summary: `${top.code}: ${top.description}`,
    employee_memory: '—',
    analysis,
    context: [
      ...context,
      { role: 'user', text: msg.user_message, at: new Date().toISOString() },
    ],
  },
}];

const msg = $input.first().json?.message;
if (!msg?.text || msg.from?.is_bot) return [];

return [{
  json: {
    chat_id: String(msg.chat.id),
    user_message: msg.text.trim(),
  },
}];

const cb = $input.first().json.callback_query?.data ?? '';
const parts = cb.split(':');
const action = parts[0] ?? '';
// WF-04 pilot: train:{action_token} | TZ: train:{dialog_id}:{action_token}
const action_token = parts.length >= 3 ? parts[2] : (parts[1] ?? '');
const dialog_id = parts.length >= 3 ? parts[1] : null;

return [{
  json: {
    action,
    action_token,
    dialog_id,
    callback_query_id: $input.first().json.callback_query.id,
  },
}];

const parse = $('Parse Callback').first().json;
const v = $input.first().json;
return [{ json: { ...v, action: parse.action, action_token: parse.action_token, callback_query_id: parse.callback_query_id } }];

